#include <iostream>
#include <string>
#include <vector>
#include <fstream>
#include <sstream>
#include <stdexcept>
#include <cstdio> // For popen/pclose

// Helper function to execute a command and capture its output
std::string exec(const char* cmd) {
    char buffer[128];
    std::string result = "";
    FILE* pipe = popen(cmd, "r");
    if (!pipe) throw std::runtime_error("popen() failed!");
    try {
        while (fgets(buffer, sizeof buffer, pipe) != NULL) {
            result += buffer;
        }
    } catch (...) {
        pclose(pipe);
        throw;
    }
    pclose(pipe);
    return result;
}

int main() {
    std::vector<std::pair<std::string, std::string>> test_cases = {
        {"10\n+\n5\n", "Enter first number: Enter operator (+, -, *, /): Enter second number: Result: 15.00\n"},
        {"20\n-\n7.5\n", "Enter first number: Enter operator (+, -, *, /): Enter second number: Result: 12.50\n"},
        {"3\n*\n4.2\n", "Enter first number: Enter operator (+, -, *, /): Enter second number: Result: 12.60\n"},
        {"10\n/\n2\n", "Enter first number: Enter operator (+, -, *, /): Enter second number: Result: 5.00\n"},
        {"10\n/\n0\n", "Enter first number: Enter operator (+, -, *, /): Enter second number: Error: Division by zero is not allowed.\nResult: 0.00\n"},
        {"10\nx\n5\n", "Enter first number: Enter operator (+, -, *, /): Enter second number: Error: Invalid operator.\nResult: 0.00\n"}
    };

    // Assume the user's code is compiled into an executable named 'calculator'
    // This driver would typically compile it first, e.g., system("g++ -o calculator solution.cpp");

    int passed_tests = 0;
    for (size_t i = 0; i < test_cases.size(); ++i) {
        const auto& tc = test_cases[i];
        std::string input = tc.first;
        std::string expected_output = tc.second;

        // Write input to a temporary file
        std::ofstream input_file("temp_input.txt");
        if (!input_file.is_open()) {
            std::cerr << "Error: Could not open temp_input.txt for writing.\n";
            return 1;
        }
        input_file << input;
        input_file.close();

        // Execute the calculator program with input redirection and capture output
        std::string command = "./calculator < temp_input.txt";
        std::string actual_output = "";
        try {
            actual_output = exec(command.c_str());
        } catch (const std::runtime_error& e) {
            std::cerr << "Execution error: " << e.what() << "\n";
            std::cout << "Test Case " << i + 1 << " Failed (Execution Error).\n";
            continue;
        }

        // Compare outputs
        if (actual_output == expected_output) {
            std::cout << "Test Case " << i + 1 << " Passed.\n";
            passed_tests++;
        } else {
            std::cout << "Test Case " << i + 1 << " Failed.\n";
            std::cout << "Input:\n" << input;
            std::cout << "Expected:\n" << expected_output;
            std::cout << "Actual:\n" << actual_output;
        }
    }

    // Clean up temporary file
    remove("temp_input.txt");

    std::cout << "\n" << passed_tests << "/" << test_cases.size() << " tests passed.\n";

    return (passed_tests == test_cases.size()) ? 0 : 1;
}
